  ('social-worker-moex-00751', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據特殊境遇家庭扶助條例，下列敘述何者錯誤？', '["將申請傷病醫療補助資格之已自行負擔醫療費用額度由3萬元上調為5萬元", "配合行政院推動組織改造，將法條中明訂之主管機關修正為衛生福利部", "專供存入各項津貼或補助之專戶，專戶內之存款不得作為扣押、抵銷、供擔保或強制執行之標的", "配合民法成年年齡下修為18歲，將有關創業貸款補助申請年齡規定，由「年滿20歲」修正為 「成年」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "2833fa197db9", "answer_pdf_sha1": "b2b06e4bb504", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00752', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據性侵害犯罪防治法，下列敘述何者錯誤？', '["犯性侵害犯罪經緩起訴確定者，不得適用任何關於加害人之規定", "兒童或心智障礙之性侵害被害人於偵查或審判階段，經司法警察、司法警察官、檢察事務官、 檢察官或法官認有必要時，應由具相關專業人士在場協助詢（訊）問", "司法人員、矯正人員及村（里）幹事人員為性侵害犯罪防治法義務通報人", "直轄市、縣（市）主管機關於知悉或接獲疑似性侵害犯罪情事通報時，應立即進行分級分類處 理，至遲不得超過24小時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "2833fa197db9", "answer_pdf_sha1": "b2b06e4bb504", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00753', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據性侵害犯罪防治法，對於性侵害犯罪的被害人，下列服務措施何者錯誤？', '["通報：醫事人員、社工人員、教育人員、保育人員、警察人員、勞政人員、司法人員、移民業 務人員、矯正人員、村（里）幹事人員，於執行職務時知有疑似性侵害犯罪情事者，應立即向 當地主管機關通報，至遲不得超過24小時，有關資訊並應保密", "驗傷及取證：對於被害人之驗傷及取證，除依刑事訴訟法、軍事審判法之規定或被害人無意識 或無法表意者外，應經被害人之同意。被害人為受監護宣告或12歲以上未滿18歲之人時，應 經其監護人或法定代理人之同意", "陪同偵訊：被害人之法定代理人、配偶、直系或三親等內旁系血親、家長、家屬、醫師、心理 師、輔導人員或社工人員得於偵查或審判中，陪同被害人在場，並得陳述意見", "給予必要補助：主管機關得依被害人之申請，核發包括非屬全民健康保險給付範圍之醫療費用 及心理復健費用、訴訟費用及律師費用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "2833fa197db9", "answer_pdf_sha1": "b2b06e4bb504", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00754', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會救助法第10條及第11條中對於生活扶助的相關規定，下列何者正確？', '["地方主管機關應自生活扶助受理申請之日起7日內派員調查", "申請生活扶助經核准者，自核准之當月生效", "生活扶助以現金給付為原則，但因實際需要，得委託適當的機構或其他家庭予以收容", "由中央主管機關統一訂定現金給付等級"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "2833fa197db9", "answer_pdf_sha1": "b2b06e4bb504", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
